example.code:
// Good
import { UserService } from "./services/user-service.js";
export class OrderService { ... }

// Bad
const { UserService } = require("./services/user-service");
module.exports = { OrderService };

// Good - named export
export interface Config { ... }
export function loadConfig(): Config { ... }

// Good - barrel at package boundary
// src/auth/index.ts
export { AuthService } from "./auth-service.js";
export type { AuthConfig } from "./types.js";

// Bad - barrel re-exporting another barrel
// src/index.ts
export * from "./auth/index.js";
export * from "./users/index.js";
export * from "./orders/index.js";

// Good
import type { User } from "./models.js";
import { UserService } from "./services.js";

function greet(user: User): string { ... }

// Good - domain defines interface, infrastructure implements
// domain/ports.ts
export interface UserRepository {
  findById(id: string): Promise<User | undefined>;
}

// infrastructure/pg-user-repository.ts
import type { UserRepository } from "../domain/ports.js";
export class PgUserRepository implements UserRepository { ... }

// Good - path alias
import { logger } from "@app/shared/logger.js";

// tsconfig.json
// "paths": { "@app/*": ["./src/*"] }
